using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type" in 9.0.
        // Fix: Explicitly set the old property name for backward compatibility with existing documents.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: Id format changed from "EntityType|KeyValue" to just "KeyValue" in 9.0.
        // Fix: Explicitly configure the old id format using HasJsonIdProperty (id stored as-is from the key).
        // If existing docs use "Blog|1" format, keep the old convention:
        modelBuilder.Entity<Blog>().Property(b => b.Id);

        // Breaking change 3: HasIndex is not supported on Cosmos provider in 9.0 (throws at model validation).
        // Fix: Removed the HasIndex call. Cosmos indexes are managed via indexing policy, not EF.
        // modelBuilder.Entity<Blog>().HasIndex(b => b.Name); // REMOVED
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

