class SyncJob
{
    void Run(BlogContext context)
    {
        // Breaking change 4: In 9.0, Cosmos provider uses patch-based (partial) updates by default
        // instead of full document replacement. Read-then-write patterns like this still work,
        // but only modified properties are sent. No code change needed here, but be aware that
        // if you rely on replacing the full document, call context.Entry(b).State = EntityState.Modified
        // or configure .HasContentPropertyJsonSerialization() as needed.
        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChanges();
    }

    // Breaking change 5: Raw SQL queries referencing "Discriminator" must be updated if you
    // did NOT apply the HasDiscriminator("Discriminator") fix above. With the fix in place,
    // existing queries like `SELECT * FROM c WHERE c.Discriminator = 'Blog'` continue to work.
    // Without the fix, you'd need: `SELECT * FROM c WHERE c["$type"] = 'Blog'`
}

